interface PromptBuilderProps {
  onAdd: (value: string, label: string, icon?: string, color?: string) => void;
  language: Language;
}

const PromptBuilder: React.FC<PromptBuilderProps> = ({ onAdd, language }) => {
  const [searchTerm, setSearchTerm] = useState('');

  const handleDragStart = (e: React.DragEvent, item: CategoryItem, cat: Category) => {
    e.dataTransfer.setData('application/gvs-tag', JSON.stringify({
      value: item.value,
      label: item.label[language],
      icon: cat.icon,
      color: cat.color
    }));
  };

  const filteredGroups = useMemo(() => {
    if (!searchTerm.trim()) return CATEGORY_GROUPS;
    
    const lowerSearch = searchTerm.toLowerCase();
    return CATEGORY_GROUPS.map(group => ({
      ...group,
      categories: group.categories.map(cat => ({
        ...cat,
        items: cat.items.filter(item => 
          item.label[language].toLowerCase().includes(lowerSearch) ||
          item.description[language].toLowerCase().includes(lowerSearch) ||
          cat.name[language].toLowerCase().includes(lowerSearch)
        )
      })).filter(cat => cat.items.length > 0)
    })).filter(group => group.categories.length > 0);
  }, [searchTerm, language]);

  return (
    <div className="space-y-12 animate-in slide-in-from-bottom duration-500 pb-20">
      {/* Search and Header */}
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h3 className="text-sm font-black text-indigo-400 uppercase tracking-[0.2em] flex items-center gap-2">
            <i className="fa-solid fa-microscope text-lg"></i>
            {language === 'zh' ? '視覺指令架構 (按 1-6 組合)' : 'Visual Blueprint (Follow 1-6)'}
          </h3>
          <p className="text-[10px] text-gray-500 font-medium mt-1">
            {language === 'zh' ? '依照數字順序選擇元素，可獲得更穩定的視覺合成結果' : 'Select elements in numerical order for superior synthesis results'}
          </p>
        </div>
        
        <div className="relative w-full sm:w-64 group">
          <i className="fa-solid fa-search absolute left-4 top-1/2 -translate-y-1/2 text-gray-500 group-focus-within:text-indigo-400 transition-colors text-xs"></i>
          <input 
            type="text" 
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            placeholder={language === 'zh' ? '搜索視覺標籤...' : 'Search tags...'} 
            className="w-full bg-black/40 border border-white/10 rounded-2xl pl-10 pr-4 py-3 outline-none focus:ring-2 focus:ring-indigo-500/50 transition-all text-[11px] font-bold"
          />
        </div>
      </div>

      {/* Render Groups */}
      {filteredGroups.map((group) => (
        <section key={group.id} className="space-y-8">
          {/* Section Header */}
          <div className="flex items-center gap-4 px-4">
             <div className="h-px flex-1 bg-gradient-to-r from-transparent via-white/10 to-transparent"></div>
             <div className="flex flex-col items-center gap-1">
                <h2 className="text-[11px] font-black uppercase tracking-[0.4em] text-gray-400 bg-black/40 px-8 py-2.5 rounded-full border border-white/5 shadow-2xl backdrop-blur-md">
                  {group.title[language]}
                </h2>
                <span className="text-[8px] text-gray-600 font-bold uppercase tracking-widest">{group.description[language]}</span>
             </div>
             <div className="h-px flex-1 bg-gradient-to-l from-transparent via-white/10 to-transparent"></div>
          </div>

          {/* Grid Container with specific Group styling */}
          <div className={`grid grid-cols-1 md:grid-cols-2 gap-6 p-6 rounded-[3.5rem] transition-all ${
            group.id === 'elements' 
              ? 'bg-indigo-500/[0.03] border border-indigo-500/10 shadow-[inset_0_0_60px_rgba(99,102,241,0.05)]' 
              : ''
          }`}>
            {group.categories.map((cat) => (
              <div 
                key={cat.id} 
                className={`glass p-6 rounded-[2.5rem] border-white/5 flex flex-col group/cat hover:bg-white/[0.02] transition-colors ${
                  group.id === 'elements' ? 'bg-black/60 shadow-xl' : 'bg-white/[0.01]'
                }`}
              >
                <div className="flex items-center justify-between mb-5">
                  <div className={`flex items-center gap-3 text-[11px] font-black uppercase tracking-widest text-gray-400 border-l-4 pl-4 ${
                    group.id === 'elements' ? 'border-purple-500/50' : 'border-indigo-500/50'
                  }`}>
                    <i className={`fa-solid ${cat.icon} ${group.id === 'elements' ? 'text-purple-400' : 'text-indigo-400'}`}></i>
                    {cat.name[language]}
                  </div>
                  {group.id === 'elements' && (
                    <span className="text-[8px] bg-purple-500/10 text-purple-400 px-2.5 py-1 rounded-lg font-black uppercase tracking-tighter border border-purple-500/20 shadow-lg">
                      Advanced
                    </span>
                  )}
                </div>
                
                <div className="flex flex-wrap gap-2.5">
                  {cat.items.map((item, idx) => (
                    <div key={idx} className="relative group/item">
                      <button
                        draggable="true"
                        onDragStart={(e) => handleDragStart(e, item, cat)}
                        onClick={() => onAdd(item.value, item.label[language], cat.icon, cat.color)}
                        className={`px-4 py-2.5 bg-white/[0.03] hover:bg-gradient-to-br ${cat.color} hover:text-white border border-white/10 rounded-2xl text-[10px] transition-all duration-300 active:scale-95 shadow-lg shadow-black/20 font-black uppercase tracking-tight flex items-center gap-2 cursor-grab active:cursor-grabbing group-hover/cat:border-white/20`}
                      >
                        <i className={`fa-solid ${cat.icon} opacity-40 text-[9px]`}></i>
                        {item.label[language]}
                      </button>
                      
                      {/* Tooltip */}
                      <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-3 w-40 hidden group-hover/item:block z-[60] pointer-events-none animate-in zoom-in duration-200">
                        <div className="bg-[#111] backdrop-blur-xl border border-white/10 p-3 rounded-2xl shadow-2xl">
                          <p className="text-[9px] text-indigo-200 leading-relaxed font-bold">
                            {item.description[language]}
                          </p>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            ))}
          </div>
        </section>
      ))}
    </div>
  );
};

export default PromptBuilder;
